            a *= 3;
            b *= 2;
            years++;
        }
        System.out.println(years);
    }
}

code.JavaScript:
const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
rl.on('line', (input) => {
    const [a, b] = input.split(' ').map(Number);
    let years = 0;
    while (a < b) {
        a *= 3;
        b *= 2;
        years++;
    }
    console.log(years);
    rl.close();
});

